  async authorize(amount: number, ctx: TxnContext): Promise<TxnResult> {
    const key = `txn:${ctx.orderId}:authorize:${ctx.attempt}`;
    const validated = this.guard.check(ctx, 'authorize');
    if (!validated.ok) {
      this.metrics.increment('authorize.rejected', { reason: validated.reason });
      return { ok: false, reason: validated.reason };
    }
    const res = await this.gateway.send({ op: 'authorize', amount, idempotencyKey: key });
    this.ledger.record(ctx.orderId, 'authorize', amount, res.id);
    this.events.emit('authorize.done', { orderId: ctx.orderId, txnId: res.id });
    return { ok: true, id: res.id };
  }

